# Here we are spliting the strings based on the spaces and then converting each part in integer and putting it in Given list
Given = [int(n) for n in string.split()]
# Defining a function to find longest increasing sequence
def longest_increasing_subsequence(data):
    n = len(data)
    lengths = [1] * n   # lengths[i] = length of the longest increasing subsequence ending at index i
    prev = [-1] * n      # prev[i] = index of the element right before i in that subsequence

    for i in range(n):
        for j in range(i):
            # can we extend the subsequence ending at j with data[i]?
            if data[j] < data[i] and lengths[j] + 1 > lengths[i]:
                lengths[i] = lengths[j] + 1
                prev[i] = j

    # find where the longest subsequence ends
    best_end = lengths.index(max(lengths))

    # walk backwards from that point to rebuild the actual sequence
    seq = []
    k = best_end
    while k != -1:
        seq.append(data[k])
        k = prev[k]
    seq.reverse()
    return seq

# Defining a function to find the longest decreasing subsequence
def longest_decreasing_subsequence(data):
    n = len(data)
    lengths = [1] * n
    prev = [-1] * n

    for i in range(n):
        for j in range(i):
            # can we extend the subsequence ending at j with data[i]? (decreasing this time)
            if data[j] > data[i] and lengths[j] + 1 > lengths[i]:
                lengths[i] = lengths[j] + 1
                prev[i] = j

    best_end = lengths.index(max(lengths))

    seq = []
    k = best_end
    while k != -1:
        seq.append(data[k])
        k = prev[k]
    seq.reverse()
    return seq


increasing = longest_increasing_subsequence(Given)
decreasing = longest_decreasing_subsequence(Given)

print(*increasing)
print()
print(*decreasing)